'use client';

import { useState } from 'react';
import { useLanguage } from '@/hooks/useLanguage';
import { Mail, MessageCircle, Phone } from 'lucide-react';

export default function Contact() {
  const { t } = useLanguage();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: '',
  });

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Contact form submission logic here
    console.log('Form submitted:', formData);
    setFormData({ name: '', email: '', message: '' });
  };

  return (
    <section id="contact" className="contact-section">
      <div className="contact-container">
        <h2
          dangerouslySetInnerHTML={{ __html: t('cta.title') }}
          className="contact-title"
        />

        <div className="contact-content">
          <div className="contact-links">
            <a href="mailto:hello@goopti.com" className="contact-link">
              <Mail size={24} />
              <span>hello@goopti.com</span>
            </a>
            <a href="https://wa.me/33712345678" className="contact-link" target="_blank">
              <MessageCircle size={24} />
              <span>WhatsApp</span>
            </a>
            <a href="tel:+33712345678" className="contact-link">
              <Phone size={24} />
              <span>+33 7 12 34 56 78</span>
            </a>
          </div>

          <form onSubmit={handleSubmit} className="contact-form">
            <div className="form-group">
              <input
                type="text"
                name="name"
                placeholder={t('cta.form.name')}
                value={formData.name}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <input
                type="email"
                name="email"
                placeholder={t('cta.form.email')}
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <textarea
                name="message"
                placeholder={t('cta.form.message')}
                value={formData.message}
                onChange={handleChange}
                rows={4}
                required
              />
            </div>
            <button type="submit" className="contact-submit">
              {t('cta.form.send')}
            </button>
          </form>
        </div>
      </div>
    </section>
  );
}
